mapper.delete:
DELETE FROM TBL_STOCK_TEMP
WHERE CMPY_CD = #{cmpyCd}
  AND WH_CD = #{whCd}

mapper.insert:
INSERT INTO TBL_STOCK_TEMP (
    CMPY_CD, WH_CD, AGNT_NM, MTRL_CD, MTRL_NM, LOC_CD, STOCK_QTY, PALT_TYPE, SAVE_TIME, SAVE_USER
) VALUES (
             #{cmpyCd}, #{whCd}, #{agntNm}, #{mtrlCd}, #{mtrlNm}, #{locCd}, #{stockQty}, #{paltType}, GETDATE(), #{saveUser}
         )

mapper.update:
UPDATE TBL_STOCK_TEMP
SET STATUS = 'C',             -- 'C'omplete (완료)
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{saveUser}
WHERE CMPY_CD = #{cmpyCd}
  AND WH_CD = #{whCd}
  AND (STATUS = 'W' OR STATUS IS NULL) -- 대기 상태인 것들만 업데이트
